/**
 * createAppStore — factory for the shared Hydra Zustand store.
 *
 * Each app calls this with its own storageKey and devtoolsName so that
 * localStorage persist keys and Redux DevTools labels are unique per app.
 */

import { del, get, set } from 'idb-keyval';
import { useCallback } from 'react';
import { create } from 'zustand';
import { createJSONStorage, devtools, persist } from 'zustand/middleware';
import { useShallow } from 'zustand/react/shallow';
import { createChatSlice } from './slices/chatSlice';
import { createSessionSlice } from './slices/sessionSlice';
import { createViewSlice } from './slices/viewSlice';
import type { ViewStoreState } from './storeTypes';
import type { ChatSession } from './types';

// Custom storage for idb-keyval
const idbStorage = {
  getItem: async (name: string): Promise<string | null> => {
    return (await get(name)) || null;
  },
  setItem: async (name: string, value: string): Promise<void> => {
    await set(name, value);
  },
  removeItem: async (name: string): Promise<void> => {
    await del(name);
  },
};

export interface AppStoreConfig {
  /**
   * localStorage key for persist middleware.
   * Must be unique per app — e.g. 'geminihydra-view', 'openaihydra-view'.
   */
  storageKey: string;
  /**
   * Label shown in Redux DevTools.
   * e.g. 'GeminiHydra/ViewStore'
   */
  devtoolsName: string;
  /**
   * localStorage persist schema version. Defaults to 2.
   * Increment when partialize shape changes to trigger migration.
   */
  persistVersion?: number;
  /**
   * Whether to enable Redux DevTools. Defaults to true.
   * Pass `import.meta.env.DEV` from the calling app for Vite-aware toggling.
   */
  devtoolsEnabled?: boolean;
}

export function createAppStore(config: AppStoreConfig) {
  const { storageKey, devtoolsName, persistVersion = 2, devtoolsEnabled = true } = config;

  const useViewStore = create<ViewStoreState>()(
    devtools(
      persist(
        (...a) => ({
          ...createViewSlice(...a),
          ...createSessionSlice(...a),
          ...createChatSlice(...a),
          _hasHydrated: false,
          setHasHydrated: (state: boolean) => a[0]({ _hasHydrated: state }),
        }),
        {
          name: storageKey,
          version: persistVersion,
          storage: createJSONStorage(() => idbStorage),
          onRehydrateStorage: () => (state) => {
            if (state) state.setHasHydrated(true);
          },
          migrate: (persisted: unknown, version: number) => {
            const state = persisted as Record<string, unknown>;
            if (version < 2) {
              // Migrate openTabs: string[] → tabs: ChatTab[]
              const openTabs = (state['openTabs'] as string[]) ?? [];
              const chatSessions = (state['chatSessions'] as ChatSession[]) ?? [];
              const activeSessionId = state['activeSessionId'] as string | null;

              const tabs = openTabs.map((sessionId: string) => {
                const session = chatSessions.find((s) => s.id === sessionId);
                return {
                  id: crypto.randomUUID(),
                  sessionId,
                  title: session?.title ?? 'New Chat',
                  isPinned: false,
                };
              });

              delete state['openTabs'];
              state['tabs'] = tabs;
              state['activeTabId'] = tabs.find((t) => t.sessionId === activeSessionId)?.id ?? null;
            }
            return state;
          },
          partialize: (state) => ({
            currentView: state.currentView,
            sidebarCollapsed: state.sidebarCollapsed,
            currentSessionId: state.currentSessionId,
            sessions: state.sessions,
            tabs: state.tabs,
            activeTabId: state.activeTabId,
          }),
        },
      ),
      { name: devtoolsName, enabled: devtoolsEnabled },
    ),
  );

  // ── Memoized selectors ──────────────────────────────────────────────────

  /** Returns the currently active Session (or undefined). Shallow-compared. */
  function useCurrentSession() {
    return useViewStore(useCallback((s: ViewStoreState) => s.sessions.find((cs) => cs.id === s.currentSessionId), []));
  }

  /** Returns the current sessions array with shallow equality. */
  function useCurrentChatHistory() {
    return useViewStore(useShallow((s: ViewStoreState) => s.sessions));
  }

  function useCurrentSessionId(): string | null {
    return useViewStore((s) => s.currentSessionId);
  }

  return { useViewStore, useCurrentSession, useCurrentChatHistory, useCurrentSessionId };
}
