import type { StateCreator } from 'zustand';
import type { ViewStoreState } from '../storeTypes';
import type { ChatSession, ChatTab } from '../types';
import { MAX_SESSIONS, MAX_TITLE_LENGTH, sanitizeTitle } from '../utils';

// GeminiHydra-style Session is now synonymous with ChatSession to support ClaudeHydra fields
export type Session = ChatSession;

export interface SessionSlice {
  sessions: Session[];
  currentSessionId: string | null;
  /**
   * Create a new session. Returns the generated session ID.
   * Accepts an optional title (defaults to "New Chat").
   * Also creates a tab for the session, switches currentView to 'chat',
   * and sets messageCount to 0.
   */
  createSession: (title?: string) => string;
  createSessionWithId: (id: string, title: string) => void;
  deleteSession: (id: string) => void;
  selectSession: (id: string) => void;
  updateSessionTitle: (id: string, title: string) => void;
  setSessionWorkingDirectory: (id: string, wd: string) => void;
  syncWorkingDirectories: (dirs: Array<{ id: string; workingDirectory: string }>) => void;
  hydrateSessions: (sessions: Session[]) => void;
  markSessionPending: (id: string, pending: boolean) => void;
  replaceSession: (tempId: string, realId: string, title: string) => void;
}

// Helper to prevent duplication in createSession and createSessionWithId
const addSessionToState = (state: ViewStoreState, newSession: Session) => {
  let sessions = [newSession, ...state.sessions];
  const changes: Partial<ViewStoreState> = {
    currentSessionId: newSession.id,
  };

  if (sessions.length > MAX_SESSIONS) {
    const removedIds = sessions.slice(MAX_SESSIONS).map((s) => s.id);
    sessions = sessions.slice(0, MAX_SESSIONS);

    const newHistory = { ...state.chatHistory };
    for (const removedId of removedIds) {
      delete newHistory[removedId];
    }
    changes.chatHistory = { ...newHistory, [newSession.id]: [] };
  } else {
    changes.chatHistory = { ...state.chatHistory, [newSession.id]: [] };
  }

  changes.sessions = sessions;
  return changes;
};

export const createSessionSlice: StateCreator<ViewStoreState, [], [], SessionSlice> = (set) => ({
  sessions: [],
  currentSessionId: null,

  createSession: (title?: string) => {
    const id = crypto.randomUUID();
    const now = Date.now();
    set((state) => {
      const sessionTitle = title ?? 'New Chat';
      const newSession: Session = {
        id,
        title: sessionTitle,
        createdAt: now,
        updatedAt: now,
        messageCount: 0,
      };
      const changes = addSessionToState(state, newSession);

      // Also create a tab for the new session and switch to chat view
      const newTab: ChatTab = {
        id: crypto.randomUUID(),
        sessionId: id,
        title: sessionTitle,
        isPinned: false,
      };
      changes.tabs = [...(state.tabs ?? []), newTab];
      changes.activeTabId = newTab.id;
      changes.currentView = 'chat';

      return changes;
    });
    return id;
  },

  createSessionWithId: (id, title) => {
    const newSession: Session = {
      id,
      title,
      createdAt: Date.now(),
    };
    set((state) => {
      if (state.sessions.some((s) => s.id === id)) {
        return { currentSessionId: id };
      }
      return addSessionToState(state, newSession);
    });
  },

  deleteSession: (id) =>
    set((state) => {
      const newSessions = state.sessions.filter((s) => s.id !== id);
      const newHistory = { ...state.chatHistory };
      delete newHistory[id];

      let newCurrentId = state.currentSessionId;
      if (state.currentSessionId === id) {
        newCurrentId = newSessions.length > 0 ? (newSessions[0]?.id ?? null) : null;
      }

      const newTabs = state.tabs.filter((t) => t.sessionId !== id);
      let newActiveTabId = state.activeTabId;
      if (state.activeTabId && !newTabs.some((t) => t.id === state.activeTabId)) {
        newActiveTabId = newTabs.length > 0 ? (newTabs[0]?.id ?? null) : null;
      }

      return {
        sessions: newSessions,
        chatHistory: newHistory,
        currentSessionId: newCurrentId,
        tabs: newTabs,
        activeTabId: newActiveTabId,
      };
    }),

  selectSession: (id) =>
    set((state) => {
      const exists = state.sessions.some((s) => s.id === id);
      if (!exists) return state;
      return { currentSessionId: id };
    }),

  updateSessionTitle: (id, title) =>
    set((state) => {
      const sanitized = sanitizeTitle(title, MAX_TITLE_LENGTH);
      return {
        sessions: state.sessions.map((s) => (s.id === id ? { ...s, title: sanitized, updatedAt: Date.now() } : s)),
        tabs: state.tabs.map((t) => (t.sessionId === id ? { ...t, title: sanitized } : t)),
      };
    }),

  setSessionWorkingDirectory: (id, wd) =>
    set((state) => ({
      sessions: state.sessions.map((s) => (s.id === id ? { ...s, workingDirectory: wd } : s)),
    })),

  syncWorkingDirectories: (dirs) =>
    set((state) => {
      const dirMap = new Map(dirs.map((d) => [d.id, d.workingDirectory]));
      let changed = false;
      const sessions = state.sessions.map((s) => {
        const dbWd = dirMap.get(s.id);
        if (dbWd !== undefined && dbWd !== (s.workingDirectory ?? '')) {
          changed = true;
          return { ...s, workingDirectory: dbWd };
        }
        return s;
      });
      return changed ? { sessions } : state;
    }),

  hydrateSessions: (dbSessions) =>
    set((state) => {
      const dbIds = new Set(dbSessions.map((s) => s.id));
      const merged = [...dbSessions, ...state.sessions.filter((s) => !dbIds.has(s.id))];

      const mergedIds = new Set(merged.map((s) => s.id));
      const currentSessionId =
        state.currentSessionId && mergedIds.has(state.currentSessionId)
          ? state.currentSessionId
          : merged.length > 0
            ? (merged[0]?.id ?? null)
            : null;

      return {
        sessions: merged,
        currentSessionId,
      };
    }),

  markSessionPending: (id, pending) =>
    set((state) => ({
      sessions: state.sessions.map((s) => (s.id === id ? { ...s, _pending: pending } : s)),
    })),

  replaceSession: (tempId, realId, title) =>
    set((state) => {
      const sessions = state.sessions.map((s) => (s.id === tempId ? { ...s, id: realId, title, _pending: false } : s));

      const newHistory = { ...state.chatHistory };
      if (newHistory[tempId]) {
        newHistory[realId] = newHistory[tempId]!;
        delete newHistory[tempId];
      }

      return {
        sessions,
        chatHistory: newHistory,
        currentSessionId: state.currentSessionId === tempId ? realId : state.currentSessionId,
        tabs: state.tabs.map((t) => (t.sessionId === tempId ? { ...t, sessionId: realId, title } : t)),
      };
    }),
});
