import { get, set } from 'idb-keyval';

export interface QueuedPrompt {
  id: string;
  sessionId: string | undefined;
  content: string;
  timestamp: number;
  mode?: string;
  model?: string;
  type: 'execute' | 'orchestrate';
  pattern?: string;
  agents?: string[];
}

const SYNC_QUEUE_KEY = 'jaskier_offline_sync_queue';

export class SyncManager {
  private static listeners: Array<() => void> = [];

  static async getQueue(): Promise<QueuedPrompt[]> {
    return (await get<QueuedPrompt[]>(SYNC_QUEUE_KEY)) || [];
  }

  static async enqueuePrompt(prompt: Omit<QueuedPrompt, 'id' | 'timestamp'>): Promise<void> {
    const queue = await SyncManager.getQueue();
    const newPrompt: QueuedPrompt = {
      ...prompt,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    await set(SYNC_QUEUE_KEY, [...queue, newPrompt]);
    SyncManager.notifyListeners();
  }

  static async clearQueue(): Promise<void> {
    await set(SYNC_QUEUE_KEY, []);
    SyncManager.notifyListeners();
  }

  static async removeFromQueue(id: string): Promise<void> {
    const queue = await SyncManager.getQueue();
    await set(
      SYNC_QUEUE_KEY,
      queue.filter((p) => p.id !== id),
    );
    SyncManager.notifyListeners();
  }

  static subscribe(listener: () => void): () => void {
    SyncManager.listeners.push(listener);
    return () => {
      SyncManager.listeners = SyncManager.listeners.filter((l) => l !== listener);
    };
  }

  private static notifyListeners() {
    SyncManager.listeners.forEach((l) => l());
  }

  static initOfflineSupport(processQueue: (prompts: QueuedPrompt[]) => Promise<void>) {
    window.addEventListener('online', async () => {
      console.log('Network is back online. Processing sync queue...');
      if ('Notification' in window && Notification.permission === 'granted') {
        new Notification('Jaskier App', { body: 'Połączenie przywrócone. Synchronizacja w tle...' });
      }

      const queue = await SyncManager.getQueue();
      if (queue.length > 0) {
        try {
          await processQueue(queue);
          await SyncManager.clearQueue();
          if ('Notification' in window && Notification.permission === 'granted') {
            new Notification('Jaskier App', { body: 'Synchronizacja zakończona pomyślnie.' });
          }
        } catch (error) {
          console.error('Failed to sync offline prompts:', error);
        }
      }
    });

    // Request notification permission if not asked yet
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }
}
