import type { StateCreator } from 'zustand';
import type { Artifact } from '../types';

export interface ViewSlice {
  currentView: string;
  sidebarCollapsed: boolean;
  /** Model ID reported by the last WS Start message (e.g. "gemini-3.1-pro-preview") */
  activeModel: string | null;
  activeArtifact: Artifact | null;
  setCurrentView: (view: string) => void;
  setActiveArtifact: (artifact: Artifact | null) => void;
  setSidebarCollapsed: (collapsed: boolean) => void;
  toggleSidebar: () => void;
  setActiveModel: (model: string) => void;
}

const SIDEBAR_STORAGE_KEY = 'jaskier_sidebar_collapsed';

function persistSidebarState(collapsed: boolean): void {
  try {
    localStorage.setItem(SIDEBAR_STORAGE_KEY, String(collapsed));
  } catch {
    /* ignore */
  }
}

export const createViewSlice: StateCreator<ViewSlice> = (set) => ({
  currentView: 'home',
  sidebarCollapsed: false,
  activeModel: null,
  activeArtifact: null,

  setCurrentView: (view) => set({ currentView: view }),
  setActiveArtifact: (artifact) => set({ activeArtifact: artifact }),
  setActiveModel: (model) => set({ activeModel: model }),

  setSidebarCollapsed: (collapsed) => {
    persistSidebarState(collapsed);
    set({ sidebarCollapsed: collapsed });
  },

  toggleSidebar: () =>
    set((state) => {
      const next = !state.sidebarCollapsed;
      persistSidebarState(next);
      return { sidebarCollapsed: next };
    }),
});
